  UserRole,
  LoyaltyType,
  SubscriptionStatus,
  SubscriptionPlan,
  CampaignType,
  CampaignStatus,
  TargetAudience,
  QRType,
  OfferType,
  RewardType,
  DeviceType,
};

// -------------------------------------------------------
// profiles
// -------------------------------------------------------
export interface Profile {
  id: string;
  role: UserRole;
  email: string;
  full_name: string | null;
  avatar_url: string | null;
  created_at: string;
  updated_at: string;
}

// -------------------------------------------------------
// merchants
